// src/components/Header.js
import React, { useState, useRef, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

// SVG avatar icon
const AvatarIcon = () => (
  <svg xmlns="http://www.w3.org/2000/svg" width="42" height="42" viewBox="0 0 16 16">
    <g transform="translate(0 -1036.362)">
      <circle cx="8" cy="1044.362" r="8" fill="#1d67b1" />
      <path fill="#2a2f3c" d="M5.978 1046.475H10v.965H5.978z" />
      <path fill="#272a4d" d="M7.186 1039.854h1.81c.823 0 1.486.74 1.486 1.658 0 .918-.663 1.657-1.486 1.657h-1.81c-.824 0-1.487-.74-1.487-1.657 0-.918.663-1.657 1.487-1.657z" />
      {/* restante omitido */}
    </g>
  </svg>
);

export default function Header() {
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const { user, logout } = useAuth();
  const navigate = useNavigate();

  const wrapperRef = useRef(null);

  // close dropdown on outside click
  useEffect(() => {
    function handleClickOutside(event) {
      if (wrapperRef.current && !wrapperRef.current.contains(event.target)) {
        setDropdownOpen(false);
      }
    }
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const toggleDropdown = () => setDropdownOpen(open => !open);

  const handlePerfil = () => {
    setDropdownOpen(false);
    navigate('/perfil');
  };

  const handleLogout = () => {
    setDropdownOpen(false);
    logout();
    navigate('/login', { replace: true });
  };

  return (
    <header className="fixed top-0 left-0 right-0 h-16 bg-white shadow flex items-center justify-between px-6 z-50">
      <h1 className="text-xl font-bold text-[#152A3F]">PoliUB Atendimentos</h1>
      <div ref={wrapperRef} className="relative">
        <button
          onClick={toggleDropdown}
          className="rounded-full focus:outline-none focus:ring-2 focus:ring-blue-400"
        >
          <AvatarIcon />
        </button>
        {dropdownOpen && (
          <ul className="absolute right-0 mt-2 w-48 bg-white border border-gray-200 rounded-lg shadow-lg">
            <li className="px-4 py-2 text-gray-700 font-medium border-b border-gray-100">
              {user?.usuario || 'Usuário'}
            </li>
            <li>
              <button
                onClick={handlePerfil}
                className="w-full text-left px-4 py-2 hover:bg-gray-100 text-gray-700"
              >
                Meu Perfil
              </button>
            </li>
            <li>
              <button
                onClick={handleLogout}
                className="w-full text-left px-4 py-2 hover:bg-gray-100 text-red-600"
              >
                Sair
              </button>
            </li>
          </ul>
        )}
      </div>
    </header>
  );
}
